def main():
    verses = json.loads(CHAPTER.read_text(encoding="utf-8"))
    added = 0
    for v in verses:
        if v["verse"] in SUMMARIES and not v["translation"].get("thai_summary"):
            v["translation"]["thai_summary"] = SUMMARIES[v["verse"]]
            added += 1
    CHAPTER.write_text(json.dumps(verses, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
    print(f"Mark 5: +{added} thai_summary entries on {len(verses)} verses.")


if __name__ == "__main__":
    main()
